// Use the metrics API response if available, else an embedded mock week
// so the report generator is demoable end-to-end.
const resp = $input.first().json;
if (resp && resp.alerts_total !== undefined) {
  return [{ json: { ...resp, source: 'metrics_api' } }];
}

return [{ json: {
  source: 'embedded_mock',
  period: { from: $now.minus({ days: 7 }).toFormat('yyyy-LL-dd'), to: $now.toFormat('yyyy-LL-dd') },
  alerts_total: 1284,
  alerts_prev_week: 1102,
  by_severity: { critical: 14, high: 156, medium: 611, low: 503 },
  by_category: { phishing: 342, malware: 187, identity: 296, cloud: 121, network: 338 },
  dispositions: { true_positive: 118, false_positive: 704, benign_true_positive: 391, open: 71 },
  mttd_minutes_avg: 11,
  mttr_minutes_avg: 187,
  mttr_prev_week: 214,
  incidents_opened: 9,
  incidents_closed: 7,
  top_fp_rules: [
    { rule: 'Impossible Travel (VPN egress)', fp_count: 212 },
    { rule: 'Mass File Download', fp_count: 96 },
    { rule: 'Rare Process Execution', fp_count: 74 }
  ],
  analyst_load: [
    { analyst: 'analyst-1', handled: 401 },
    { analyst: 'analyst-2', handled: 388 },
    { analyst: 'analyst-3', handled: 424 }
  ],
  automation: { auto_triaged: 897, auto_contained_approved: 3, approvals_denied: 1, llm_analyst_agreement_pct: 87 }
} }];

// Derive the KPIs both report audiences care about. Pure arithmetic —
// numbers are computed here, never by the LLM.
const m = $input.first().json;
const closed = (m.dispositions.true_positive ?? 0) + (m.dispositions.false_positive ?? 0) + (m.dispositions.benign_true_positive ?? 0);
const pct = (a, b) => b ? Math.round((a / b) * 1000) / 10 : null;

return [{ json: {
  ...m,
  kpis: {
    alert_volume_delta_pct: pct(m.alerts_total - m.alerts_prev_week, m.alerts_prev_week),
    tp_rate_pct: pct(m.dispositions.true_positive, closed),
    fp_rate_pct: pct(m.dispositions.false_positive, closed),
    closure_rate_pct: pct(closed, m.alerts_total),
    mttr_minutes: m.mttr_minutes_avg,
    mttr_delta_pct: pct(m.mttr_minutes_avg - m.mttr_prev_week, m.mttr_prev_week),
    mttd_minutes: m.mttd_minutes_avg,
    auto_triage_coverage_pct: pct(m.automation?.auto_triaged ?? 0, m.alerts_total),
    worst_fp_rule: m.top_fp_rules?.[0]?.rule ?? 'n/a',
    worst_fp_share_pct: pct(m.top_fp_rules?.[0]?.fp_count ?? 0, m.dispositions.false_positive),
  },
} }];

// Assemble the full HTML report. All numbers rendered from Compute KPIs
// directly; LLM sections are prose only.
const parse = raw => {
  let o = raw?.message?.content ?? raw?.output ?? {};
  if (typeof o === 'string') { try { o = JSON.parse((o.match(/\{[\s\S]*\}/) || ['{}'])[0]); } catch (e) { o = {}; } }
  return o;
};
const exec = parse($('LLM: Executive Summary').first().json);
const ops = parse($('LLM: Analyst Detail').first().json);
const m = $('Compute KPIs').first().json;
const k = m.kpis;
const arrow = v => v === null ? '' : v > 0 ? `▲ +${v}%` : v < 0 ? `▼ ${v}%` : '→ 0%';

const html = `<!DOCTYPE html><html><head><meta charset="utf-8"><style>
body{font-family:Segoe UI,Arial,sans-serif;font-size:14px;color:#222;max-width:860px;margin:auto;padding:24px}
h1{border-bottom:3px solid #2c3e50}h2{color:#2c3e50;margin-top:28px}
.kpi{display:inline-block;min-width:150px;margin:6px;padding:12px;border:1px solid #ddd;border-radius:6px;text-align:center}
.kpi b{font-size:22px;display:block}table{border-collapse:collapse;width:100%}td,th{border:1px solid #ddd;padding:6px;text-align:left}
.warn{color:#c0392b}</style></head><body>
<h1>SOC Weekly Report — ${m.period.from} → ${m.period.to}</h1>
<p><i>Data source: ${m.source} · generated ${new Date().toISOString()}</i></p>

<h2>Executive Summary</h2>
<p><b>${exec.headline ?? ''}</b></p>
<ul>${(exec.key_points ?? []).map(p => `<li>${p}</li>`).join('')}</ul>
${(exec.risk_callouts ?? []).length ? `<p class="warn"><b>Risk callouts:</b></p><ul>${exec.risk_callouts.map(r => `<li class="warn">${r}</li>`).join('')}</ul>` : ''}

<h2>KPIs</h2>
<div>
<span class="kpi"><b>${m.alerts_total}</b>alerts (${arrow(k.alert_volume_delta_pct)})</span>
<span class="kpi"><b>${k.tp_rate_pct}%</b>true-positive rate</span>
<span class="kpi"><b>${k.fp_rate_pct}%</b>false-positive rate</span>
<span class="kpi"><b>${k.mttr_minutes}m</b>MTTR (${arrow(k.mttr_delta_pct)})</span>
<span class="kpi"><b>${k.mttd_minutes}m</b>MTTD</span>
<span class="kpi"><b>${k.auto_triage_coverage_pct}%</b>auto-triage coverage</span>
</div>

<h2>Alert Breakdown</h2>
<table><tr><th>Severity</th>${Object.keys(m.by_severity).map(s => `<th>${s}</th>`).join('')}</tr>
<tr><td>Count</td>${Object.values(m.by_severity).map(v => `<td>${v}</td>`).join('')}</tr></table>
<br/>
<table><tr><th>Category</th>${Object.keys(m.by_category).map(s => `<th>${s}</th>`).join('')}</tr>
<tr><td>Count</td>${Object.values(m.by_category).map(v => `<td>${v}</td>`).join('')}</tr></table>

<h2>Analyst / Operations Detail</h2>
<ul>${(ops.notable_patterns ?? []).map(p => `<li>${p}</li>`).join('')}</ul>
<h3>Tuning recommendations</h3>
<table><tr><th>Rule</th><th>Recommendation</th><th>Expected impact</th></tr>
${(ops.tuning_recommendations ?? []).map(t => `<tr><td>${t.rule}</td><td>${t.recommendation}</td><td>${t.expected_impact}</td></tr>`).join('')}</table>
<p>${ops.automation_notes ?? ''}</p>
<h3>Next week focus</h3>
<ul>${(ops.next_week_focus ?? []).map(p => `<li>${p}</li>`).join('')}</ul>

<h2>Top FP-generating rules</h2>
<table><tr><th>Rule</th><th>FP count</th></tr>
${(m.top_fp_rules ?? []).map(r => `<tr><td>${r.rule}</td><td>${r.fp_count}</td></tr>`).join('')}</table>
</body></html>`;

return [{ json: {
  html,
  subject: `[SOC] Weekly report ${m.period.from} → ${m.period.to}: ${m.alerts_total} alerts, TP ${k.tp_rate_pct}%, MTTR ${k.mttr_minutes}m`,
  filename: `soc-weekly-${m.period.to}.html`,
} }];
